#include <bits/stdc++.h>
using namespace std;
struct student
{
    int num;
    int b;
    int c;
};
int main()
{
    int n;
    cin>>n;
    student stu[1005];
    for(int i=0;i<=n-1;i++)
    {
        cin>>stu[i].num>>stu[i].b>>stu[i].c;
    }
    for(int i=0;i<=n-1;i++)
    {
        if((stu[i].b+stu[i].c)>140&&(stu[i].b*7+stu[i].c*3)>=800)
        {
            cout<<"Excellent"<<endl;
        }
        else
        {
            cout<<"Not excellent"<<endl;
        }
    }
}
